package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithTrim() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        boolean trim = true;

        // When
        Method withTrimMethod = CSVFormat.class.getDeclaredMethod("withTrim", boolean.class);
        withTrimMethod.setAccessible(true);
        CSVFormat updatedCsvFormat = (CSVFormat) withTrimMethod.invoke(csvFormat, trim);

        // Then
        assertNotNull(updatedCsvFormat);
        assertEquals(trim, updatedCsvFormat.getTrim());
    }
}
